callGraph.callee:
keys
    .map((key) => {
      const isConflict = conflictSet.has(key) || conflictSet.has('*');
      const localVal = formatConflictValue(localData?.[key], key);
      const serverVal = formatConflictValue(serverData?.[key], key);
      const serverMissing = serverData?.[key] === undefined || serverData?.[key] === null;
      const samePreview = localVal === serverVal && localVal !== '—';
      return (
        '<article class="clinical-conflict-field-card' +
        (isConflict ? ' clinical-conflict-field-card--hot' : '') +
        '">' +
        '<h4 class="clinical-conflict-field-title">' +
        escHtml(formatFieldLabel(key)) +
        '</h4>' +
        (samePreview
          ? '<p class="clinical-conflict-field-same">En este resumen se ve igual en tu borrador y en la sala; aun así el registro del host no coincide del todo (versión, metadatos u otro campo que aquí no mostramos).</p>'
          : '<div class="clinical-conflict-compare">' +
            '<div class="clinical-conflict-side clinical-conflict-side--local">' +
            '<span class="clinical-conflict-side-label">Tu intento</span>' +
            '<p>' +
            escHtml(localVal) +
            '</p></div>' +
            '<div class="clinical-conflict-side clinical-conflict-side--server' +
            (serverMissing ? ' clinical-conflict-side--missing' : '') +
            '">' +
            '<span class="clinical-conflict-side-label">En la sala</span>' +
            '<p>' +
            escHtml(serverVal) +
            '</p></div></div>') +
        '</article>'
      );
    })
    .join

clearAllDraftConflicts()
      .then(function (cleared) {
        var toast = conflictDeps.showToast;
        if (typeof toast === 'function') {
          toast(
            cleared
              ? 'Se descartaron ' + cleared + ' conflictos antiguos.'
              : 'No había borradores que descartar.',
            cleared ? 'success' : 'info'
          );
        }
      })
      .catch(function () {
        if (typeof conflictDeps.showToast === 'function') {
          conflictDeps.showToast('No se pudieron descartar los borradores.', 'error');
        }
      })
      .finally

clearAllDraftConflicts()
      .then(function (cleared) {
        var toast = conflictDeps.showToast;
        if (typeof toast === 'function') {
          toast(
            cleared
              ? 'Se descartaron ' + cleared + ' conflictos antiguos.'
              : 'No había borradores que descartar.',
            cleared ? 'success' : 'info'
          );
        }
      })
      .catch

(rows || [])
    .map(function (row) {
      const id = String(row.id || '');
      let local = localById.get(id) || null;
      const reg = String(row.registro || '').trim();
      if (!local && reg) {
        const byReg = localByRegistro.get(reg);
        if (byReg && String(byReg.id) === id) {
          local = byReg;
        }
      }
      const status = local ? 'local' : 'ghost';
      return {
        row: row,
        local: local,
        status: status,
        inactive: isInactiveHostPatientRow(row, local, status),
      };
    })
    .sort

(async function () {
      /** @type {{ prefixes?: string[], candidateBaseUrl?: string }} */
      var payload = {};
      if (window.electronAPI?.getLanSubnetPrefixes && window.electronAPI?.getLanCandidateBaseUrl) {
        try {
          var prefixes = await window.electronAPI.getLanSubnetPrefixes();
          var candidateBaseUrl = await window.electronAPI.getLanCandidateBaseUrl();
          payload = { prefixes: prefixes || [], candidateBaseUrl: candidateBaseUrl || '' };
        } catch (_eOnline) {}
      }
      var m = await import('../../lan-network-change.mjs');
      if (typeof m.handleLanNetworkChanged === 'function') {
        await m.handleLanNetworkChanged(payload);
      }
    })

(async function () {
    const { isClinicalLocalOnlyMode, readRpcSettings } = await import('../../clinical-settings.mjs');
    if (isClinicalLocalOnlyMode(readRpcSettings())) return;
    const pin = await import('../../lan-shift-pin-connect.mjs');
    if (typeof pin.tryEasyLanShiftPinConnect === 'function') {
      await pin.tryEasyLanShiftPinConnect({ silent: true });
    }
    await initLanHostPlugAndPlay();
  })
